import { cfg } from "../lib/config.js";
import { aiChat, extractChatContent } from "../lib/ai.js";
import { addTurn, getRecentTurns } from "../lib/memory.js";
import { buildBotProfile } from "../lib/botProfile.js";
import { safeErr } from "../lib/safeErr.js";

const inflightByKey = new Map();
let globalInflight = 0;

function clampText(s, maxChars) {
  const t = String(s || "").trim();
  if (t.length <= maxChars) return t;
  return t.slice(0, maxChars) + "…";
}

function extractUrl(text) {
  const t = String(text || "");
  const m = t.match(/https?:\/\/[^\s)\]}>,"']+/i);
  return m ? m[0] : "";
}

function keyFor(ctx) {
  const userId = String(ctx.from?.id || "");
  const chatId = String(ctx.chat?.id || "");
  return userId ? `u:${userId}` : `c:${chatId}`;
}

function truncateAtParagraphBoundary(text, maxChars) {
  const t = String(text || "").trim();
  if (t.length <= maxChars) return t;

  const slice = t.slice(0, maxChars);
  const idx = Math.max(slice.lastIndexOf("\n\n"), slice.lastIndexOf("\n"));

  if (idx > Math.floor(maxChars * 0.6)) {
    return slice.slice(0, idx).trim() + "\n\n(Trimmed.)";
  }

  const idx2 = Math.max(slice.lastIndexOf(". "), slice.lastIndexOf(".\n"), slice.lastIndexOf("; "));
  if (idx2 > Math.floor(maxChars * 0.6)) {
    return slice.slice(0, idx2 + 1).trim() + " (Trimmed.)";
  }

  return slice.trim() + "…";
}

function buildSystemPrompt({ hasUrl }) {
  const botProfile = buildBotProfile();

  const style = [
    "You are a VC/investor doing a fast, high-signal evaluation.",
    "Be crisp, analytical, and slightly blunt about the business. Always respectful to the person.",
    "Plain text only. No markdown.",
    "Default to short output that fits a quick Telegram read.",
    "If critical info is missing that blocks TAM/CAC/moat assessment, ask at most 2 questions at the end.",
    "Do not ask questions unless it materially changes the evaluation.",
    "",
    "You MUST follow the required output structure exactly and keep each section short.",
    "Red flags: up to 3 items max.",
    "Next steps: exactly 2 actions.",
  ].join("\n");

  const linkNote = hasUrl
    ? "\n\nUser included a URL. You may comment on positioning/landing-page clarity, but do not claim you browsed the page unless the user explicitly pasted content."
    : "";

  return botProfile + "\n\n" + style + linkNote;
}

export function registerAgent(bot) {
  bot.on("message:text", async (ctx, next) => {
    const raw = ctx.message?.text || "";
    if (raw.startsWith("/")) return next();

    const k = keyFor(ctx);

    if (inflightByKey.get(k)) {
      await ctx.reply("I’m working on your last one—give me a sec.");
      return;
    }

    const cap = Number.isFinite(cfg.GLOBAL_INFLIGHT_CAP) ? cfg.GLOBAL_INFLIGHT_CAP : 2;
    if (globalInflight >= Math.max(1, cap)) {
      await ctx.reply("Busy, try again in a moment.");
      return;
    }

    inflightByKey.set(k, true);
    globalInflight++;

    try {
      const userId = String(ctx.from?.id || "");
      const chatId = String(ctx.chat?.id || "");

      const url = extractUrl(raw);
      const hasUrl = !!url;

      const userText = clampText(raw, 6000);

      await addTurn({
        mongoUri: cfg.MONGODB_URI,
        platform: "telegram",
        userId,
        chatId,
        role: "user",
        text: userText,
      });

      const history = await getRecentTurns({
        mongoUri: cfg.MONGODB_URI,
        platform: "telegram",
        userId,
        chatId,
        limit: 18,
      });

      const system = buildSystemPrompt({ hasUrl });

      const messages = [
        { role: "system", content: system },
        ...history.map((m) => ({
          role: m.role === "assistant" ? "assistant" : "user",
          content: clampText(m.text, 1600),
        })),
        {
          role: "user",
          content:
            (hasUrl
              ? `Submission (includes URL: ${url}):\n${userText}`
              : `Submission:\n${userText}`) +
            "\n\nRespond using the required short-form VC structure.",
        },
      ];

      const res = await aiChat(
        cfg,
        {
          messages,
          meta: {
            platform: "telegram",
            userId,
            chatId,
            feature: "vc_roast",
            hasUrl,
          },
        },
        { timeoutMs: cfg.AI_TIMEOUT_MS, retries: cfg.AI_MAX_RETRIES }
      );

      if (!res.ok) {
        console.log("[agent] ai failed", { status: res.status, err: res.error });
        await ctx.reply("I couldn’t finish the analysis right now. Try again in a bit.");
        return;
      }

      let out = extractChatContent(res.json);
      if (!out) {
        console.log("[agent] ai missing output", { keys: Object.keys(res.json || {}) });
        await ctx.reply("I got an empty response back. Try again with a bit more detail.");
        return;
      }

      const maxChars = Number(process.env.AI_SHORT_MAX_CHARS || 1600);
      out = truncateAtParagraphBoundary(out, Number.isFinite(maxChars) && maxChars > 300 ? maxChars : 1600);

      await addTurn({
        mongoUri: cfg.MONGODB_URI,
        platform: "telegram",
        userId,
        chatId,
        role: "assistant",
        text: out,
      });

      await ctx.reply(out);
    } catch (e) {
      console.log("[agent] handler error", { err: safeErr(e) });
      await ctx.reply("Something went wrong. Try again in a moment.");
    } finally {
      inflightByKey.delete(k);
      globalInflight = Math.max(0, globalInflight - 1);
    }
  });
}

index.js.content:
import "dotenv/config";

import { run } from "@grammyjs/runner";
import { GrammyError, HttpError } from "grammy";

import { cfg } from "./lib/config.js";
import { safeErr } from "./lib/safeErr.js";
import { createBot } from "./bot.js";
import { ensureMemoryIndexes } from "./lib/memory.js";

process.on("unhandledRejection", (r) => {
  console.log("[fatal] unhandledRejection", { err: safeErr(r) });
  process.exit(1);
});

process.on("uncaughtException", (e) => {
  console.log("[fatal] uncaughtException", { err: safeErr(e) });
  process.exit(1);
});

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function is409(err) {
  const msg = String(err?.message || "");
  return msg.includes("409") || msg.toLowerCase().includes("conflict");
}

let runner = null;
let restarting = false;

async function startPollingWithRetry(bot) {
  if (runner) return;

  const delays = [2000, 5000, 10000, 20000];
  let i = 0;

  while (true) {
    try {
      await bot.api.deleteWebhook({ drop_pending_updates: true });
      console.log("[boot] polling start", { concurrency: cfg.CONCURRENCY });

      runner = run(bot, { concurrency: cfg.CONCURRENCY });
      return;
    } catch (e) {
      const err = safeErr(e);

      if (!is409(e)) {
        console.log("[boot] polling start failed", { err });
        throw e;
      }

      const d = delays[Math.min(i, delays.length - 1)];
      console.log("[boot] 409 conflict, retrying", { inMs: d });
      i++;
      await sleep(d);
    }
  }
}

async function restartPolling(bot) {
  if (restarting) return;
  restarting = true;

  try {
    if (runner) {
      try {
        runner.abort();
      } catch {}
      runner = null;
      await sleep(1000);
    }

    await startPollingWithRetry(bot);
  } finally {
    restarting = false;
  }
}

async function boot() {
  console.log("[boot] starting", {
    TELEGRAM_BOT_TOKEN_set: !!cfg.TELEGRAM_BOT_TOKEN,
    MONGODB_URI_set: !!cfg.MONGODB_URI,
    COOKMYBOTS_AI_ENDPOINT_set: !!cfg.COOKMYBOTS_AI_ENDPOINT,
    COOKMYBOTS_AI_KEY_set: !!cfg.COOKMYBOTS_AI_KEY,
  });

  if (!cfg.TELEGRAM_BOT_TOKEN) {
    console.log("TELEGRAM_BOT_TOKEN is required. Set it and redeploy.");
    process.exit(1);
  }

  if (!cfg.MONGODB_URI) {
    console.log("[boot] warning: MONGODB_URI not set; using in-memory fallback for memory");
  } else {
    await ensureMemoryIndexes(cfg.MONGODB_URI);
  }

  const bot = await createBot(cfg.TELEGRAM_BOT_TOKEN);

  bot.catch(async (err) => {
    const e = err.error;

    if (e instanceof GrammyError) {
      console.log("[telegram] GrammyError", {
        method: e.method,
        description: e.description,
      });

      if (String(e.description || "").includes("Conflict") || is409(e)) {
        await restartPolling(bot);
      }

      return;
    }

    if (e instanceof HttpError) {
      console.log("[telegram] HttpError", { err: safeErr(e) });
      return;
    }

    console.log("[telegram] unknown error", { err: safeErr(e) });
  });

  // Ensure ctx.me is available
  try {
    await bot.init();
  } catch (e) {
    console.log("[boot] bot.init failed", { err: safeErr(e) });
  }

  try {
    await bot.api.setMyCommands([
      { command: "start", description: "What this bot does" },
      { command: "help", description: "Examples and output format" },
      { command: "reset", description: "Clear your stored memory" },
    ]);
  } catch (e) {
    console.log("[boot] setMyCommands failed", { err: safeErr(e) });
  }

  // Memory log occasionally
  setInterval(() => {
    const m = process.memoryUsage();
    console.log("[mem]", {
      rssMB: Math.round(m.rss / 1e6),
      heapUsedMB: Math.round(m.heapUsed / 1e6),
    });
  }, 60_000).unref();

  await startPollingWithRetry(bot);
}

boot().catch((e) => {
  console.log("[boot] fatal", { err: safeErr(e) });
  process.exit(1);
});

ai.js.content:
import { safeErr } from "./safeErr.js";

function trimSlash(u) {
  u = String(u || "");
  while (u.endsWith("/")) u = u.slice(0, -1);
  return u;
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function withTimeout(ms) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), ms);
  return { ctrl, clear: () => clearTimeout(t) };
}

function pickTimeoutMs(cfg, override) {
  const v = Number(override ?? cfg?.AI_TIMEOUT_MS ?? 600000);
  return Number.isFinite(v) && v > 0 ? v : 600000;
}

function endpoint(cfg, path) {
  const base = trimSlash(cfg?.COOKMYBOTS_AI_ENDPOINT || "");
  return base ? base + path : "";
}

function cfgOk(cfg) {
  return !!(cfg?.COOKMYBOTS_AI_ENDPOINT && cfg?.COOKMYBOTS_AI_KEY);
}

async function readJsonOrText(r) {
  const text = await r.text();
  try {
    return { text, json: JSON.parse(text) };
  } catch {
    return { text, json: null };
  }
}

export async function aiChat(cfg, { messages, model = "", meta = {} } = {}, opts = {}) {
  const timeoutMs = pickTimeoutMs(cfg, opts.timeoutMs);
  const retries = Number.isFinite(opts.retries) ? Number(opts.retries) : Number(cfg?.AI_MAX_RETRIES ?? 2);

  if (!cfgOk(cfg)) {
    return {
      ok: false,
      status: 412,
      json: null,
      error: "AI_NOT_CONFIGURED",
    };
  }

  const url = endpoint(cfg, "/chat");

  for (let attempt = 0; attempt <= retries; attempt++) {
    const { ctrl, clear } = withTimeout(timeoutMs);
    const startedAt = Date.now();

    try {
      console.log("[ai] chat start", {
        attempt,
        timeoutMs,
        hasModel: !!String(model || "").trim(),
        msgCount: Array.isArray(messages) ? messages.length : 0,
      });

      const r = await fetch(url, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${cfg.COOKMYBOTS_AI_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          messages: Array.isArray(messages) ? messages : [],
          model: String(model || "").trim() || undefined,
          meta: meta || undefined,
        }),
        signal: ctrl.signal,
      });

      const { text, json } = await readJsonOrText(r);

      if (!r.ok) {
        const msg = json?.error || json?.message || text || `AI_HTTP_${r.status}`;
        console.log("[ai] chat fail", {
          status: r.status,
          ms: Date.now() - startedAt,
          err: String(msg).slice(0, 300),
        });

        if (attempt < retries && (r.status === 408 || r.status === 429 || r.status >= 500)) {
          await sleep(500 * (attempt + 1));
          continue;
        }

        return { ok: false, status: r.status, json, error: String(msg) };
      }

      console.log("[ai] chat ok", { status: r.status, ms: Date.now() - startedAt });
      return { ok: true, status: r.status, json, error: null };
    } catch (e) {
      const msg = e?.name === "AbortError" ? "AI_TIMEOUT" : safeErr(e);
      console.log("[ai] chat exception", { attempt, err: String(msg).slice(0, 300) });

      if (attempt < retries) {
        await sleep(500 * (attempt + 1));
        continue;
      }

      return { ok: false, status: e?.name === "AbortError" ? 408 : 0, json: null, error: String(msg) };
    } finally {
      clear();
    }
  }

  return { ok: false, status: 0, json: null, error: "AI_UNKNOWN" };
}

export function extractChatContent(json) {
  const content = json?.output?.content;
  if (typeof content === "string" && content.trim()) return content.trim();

  const alt = json?.result?.output_text;
  if (typeof alt === "string" && alt.trim()) return alt.trim();

  return "";
}

